import scala.collection.mutable.PriorityQueue

def solve(value: Array[Long], limit: Array[Long]): Long = {
    val n = value.length
    val indices = (0 until n).toArray
    // Sort indices based on limit in ascending order, then value in descending order
    val sortedIndices = indices.sortBy(i => (limit(i), -value(i)))

    var activeCount = 0L
    var total = 0L
    val maxHeap = PriorityQueue.empty[Long](Ordering[Long].reverse)

    for (i <- sortedIndices) {
        val l = limit(i)
        val v = value(i)
        // While activeCount >= l, we need to deactivate elements
        while (activeCount >= l && maxHeap.nonEmpty) {
            activeCount -= 1
            maxHeap.dequeue()
        }
        if (activeCount < l) {
            maxHeap.enqueue(v)
            activeCount += 1
            total += v
        }
    }

    total
}
